const { env } = require('@nordic/env');

const cronStorage = require('./storage');
const { createCronManager } = require('./manager');
const { handleWorkerSend, handleCluster } = require('./cluster');
const { onNewOnlineWorker } = require('./cluster/utils');

/**
 * @param {Array} jobConfigs
 */
function initCronJobs(jobConfigs) {
  if (env.TEST) {
    return;
  }

  // same validation than ragnar
  if (!env.PRODUCTION || env.DISABLE_NODEJS_CLUSTER === 'true') {
    createCronManager({ jobConfigs, startNow: true });

    return;
  }

  const cronManager = createCronManager({
    jobConfigs,
    onTick: handleWorkerSend,
  });

  handleCluster({
    onOnline: cronManager.start.bind(cronManager),
    onMessage: cronStorage.set.bind(cronStorage),
    onNewOnlineWorker,
  });
}

module.exports = {
  initCronJobs,
};
